sql:
SELECT COUNT(profile_id) 
FROM premium_rate_requests 
WHERE status = 'pending';

SELECT COUNT(profile_id) 
FROM driver_profile_updates
WHERE update_date > '2022-07-01';

SELECT profile_id, COUNT(violation_id) AS total_violations, SUM(fine_amount) AS total_fines
FROM speeding_violations
GROUP BY profile_id;

SELECT driver_name, license_state
FROM driver_profiles
WHERE license_state IN ('CA', 'NY');

SELECT COUNT(dui_id) AS total_dui_incidents
FROM duis
WHERE blood_alcohol_level > 0.08;

external_knowledge:
- 'sailed through their driving history without a single blemish' refers to drivers with a clean record;
- 'born during the dawn of the millennial wave' refers to drivers born between 1980 and 1995;
- 'higher than the ocean's tide that rose after the year 2020' refers to an average premium rate higher than the average premium rate of all rates that became effective after January 1, 2020.

sql:
SELECT pr.premium_rate AS min_premium_rate, pr.effective_date
FROM premium_rates pr
WHERE pr.premium_rate = (
  SELECT MIN(premium_rate)
  FROM premium_rates
);

SELECT license_number 
FROM driver_profiles 
WHERE profile_id = 1;

external_knowledge:
- 'average premium rate' refers to the mean value of all premium rates for a specific combination of company and profile;
- 'earliest effective date' is the first date when any of the rates for a specific combination becomes effective;
- 'latest expiration date' is the last date when any of the rates for a specific combination expires;
- 'number of rates' is the total count of different rate entries for a specific combination.

- "most frequently caught speeding" refers to the highest number of speeding violations;
- "insurance companies" are entities that provide insurance coverage to drivers;
- "premium rates" are the amounts charged by insurance companies for coverage.

- "Driver history" includes records of speeding violations and accidents;
- "Premium rates" are influenced by the driver's history, with higher rates for drivers with more violations or severe accidents;
- "Accident severity" is categorized into major and minor, with major accidents potentially leading to higher premium rates.

- 'infraction' refers to any of the following: speeding violations, accidents, or DUIs;
- 'highest premium rate per infraction' is calculated by dividing the premium rate by the sum of total violations, accidents, and DUIs, plus one;
- 'specified date' is '2022-14-01', which is a placeholder for a specific date in the query.

- A speeding violation is an offense for driving over the legal speed limit;
- Accident severity levels are categorized as minor, major, etc., indicating the seriousness of the accident;
- The premium rate increase is a financial adjustment applied to the insurance premium based on the driver's violation history and accident severity.

sql:
SELECT
    (SELECT COUNT(request_id) FROM premium_rate_requests WHERE status = 'approved') AS total_approved_requests,
    (SELECT SUM(fine_amount) FROM duis WHERE blood_alcohol_level > 0.08) AS total_dui_fine_amount;

external_knowledge:
- "Leaders" refers to companies with an average premium rate greater than the overall average premium rate;
- "Soar above the horizon" is a metaphor for being higher than a benchmark;
- "Average premium rate" is the mean value of premium rates for a specific company or across all companies.

sql:
SELECT profile_id, violation_date, fine_amount
FROM speeding_violations
ORDER BY fine_amount DESC;

external_knowledge:
- "Navigated through a storm of accidents" refers to drivers who have been involved in multiple accidents;
- "Weight of their insurance burdens" refers to the total premium rate they have accumulated;
- "Carrying the heaviest burdens" means the drivers with the highest total premium rates.

sql:
SELECT driver_name, date_of_birth
FROM driver_profiles
ORDER BY date_of_birth ASC;

external_knowledge:
- 'significant financial penalties' refers to fine amounts greater than 100.0;
- 'past year' refers to the period between '2022-01-01' and '2022-12-31';
- 'industry average' refers to the average premium rate across all insurance companies.

sql:
SELECT profile_id, speed_limit
FROM speeding_violations
WHERE actual_speed > speed_limit;
